mapper.select:
    /* AppLisk01Mapper."selectRiskType" */
    SELECT
		PROCESS_CD
	    , RISK_TYPE_CD
	    , RISK_TYPE_NM
	FROM TB_RISK_TYPE
	WHERE CMPNY_CD = #{token.gv_cmpnyCd}
	  AND (
		SITE_CD IS NULL OR
		SITE_CD = '' OR
		SITE_CD = #{param.siteCd}
	  )
	  AND USE_YN = 'Y'

    /* AppLisk01Mapper."selectRiskHazard" */
    SELECT 
    	RISK_TYPE_CD
    	, HAZARD_CD
    	, HAZARD_NM
	FROM TB_RISK_SITE_HAZARD
	WHERE CMPNY_CD = #{token.gv_cmpnyCd}
	  AND (
		SITE_CD IS NULL OR
		SITE_CD = '' OR 
		SITE_CD = #{param.siteCd}
	  )
	  AND USE_YN = 'Y'

mapper.insert:
/* AppLisk01Mapper.mergeRiskAssessment */
INSERT INTO TB_RISK_ASSESSMENT (
	CMPNY_CD
	, SITE_CD
	, PROCESS_CD
	, RISK_TYPE_CD
	, HAZARD_CD
	, ASSESSMENT_CD
	, ASSESSMENT_DESC
	, ASSESSMENT_STATUS

	, INIT_LIKELIHOOD_SCORE			-- 개선 전 발생빈도
	, INIT_SEVERITY_SCORE			-- 개선 전 발생빈도
	, INIT_RISK_LV					-- 개선 전 위험성 level
	, INIT_DESC						-- 유해요인설명
	, INIT_FILE_MGMT_CD				-- 유해요인 사진
	, INIT_ASSESSOR_ID				-- 초기평가자
	, INIT_ASSESS_DATE				-- 초기평가일시

	, INSERT_NO						-- 입력자
	, INSERT_DATE					-- 입력일시
	, UPDATE_NO						-- 수정자
	, UPDATE_DATE					-- 수정일시
)

VALUES (
	#{token.gv_cmpnyCd}
	, #{param.siteCd}
	, #{param.processCd}
	, #{param.riskTypeCd}
	, #{param.hazardCd}
	, CONCAT(DATE_FORMAT(NOW(), '%y%m'), FNC_CMM_SEQ_NEXTVAL(#{token.gv_cmpnyCd}, 'ASSESSMENT'))
	, #{param.assessmentDesc}
	, #{param.assessmentStatus}

	, #{param.initLikelihoodScore}
	, #{param.initSeverityScore}
	, IFNULL(#{param.initLikelihoodScore}, 1) * IFNULL(#{param.initSeverityScore}, 1) 

	, #{param.initDesc}
	, #{param.initFileMgmtCd}
	, #{token.gv_userId}
	, now()

	, #{token.gv_userId}
	, now()
	, #{token.gv_userId}
	, now()
)
ON DUPLICATE KEY UPDATE
    ASSESSMENT_STATUS 			= VALUES(ASSESSMENT_STATUS)
    , INIT_LIKELIHOOD_SCORE		= VALUES(INIT_LIKELIHOOD_SCORE)
    , INIT_SEVERITY_SCORE		= VALUES(INIT_SEVERITY_SCORE)
    , INIT_RISK_LV 				= VALUES(INIT_RISK_LV)
    , INIT_DESC					= VALUES(INIT_DESC)
    , INIT_FILE_MGMT_CD			= VALUES(INIT_FILE_MGMT_CD)

    , UPDATE_NO   		= #{token.gv_userId}
    , UPDATE_DATE 		= NOW()

	/* AppChkLst01Mapper.mergeChkptInspectAnswer */	
    INSERT INTO TB_CHKPT_INSPECT_ANSWER (
    	CMPNY_CD
    	, SITE_CD
    	, INSPECT_ITEM_CD
    	, WORK_DATE
    	, INSPECT_ANSWER_TYPE
    	, ANSWER_DESC
    	, FILE_MGMT_CD
    	, INSERT_NO
    	, INSERT_DATE
    	, UPDATE_NO
    	, UPDATE_DATE
   	)
   	VALUES(
   		#{token.gv_cmpnyCd}
   		, #{param.siteCd}
   		, #{param.inspectItemCd}
   		, #{param.workDate}
   		, #{param.inspectAnswerType}
   		, #{param.answerDesc}
   		, #{param.fileMgmtCd}		
		, #{token.gv_userId}
		, now()
		, #{token.gv_userId}
		, now() 
   	)
   	ON DUPLICATE KEY UPDATE
	    INSPECT_ANSWER_TYPE = VALUES(INSPECT_ANSWER_TYPE)
	    , ANSWER_DESC 		= VALUES(ANSWER_DESC)
	    , FILE_MGMT_CD		= VALUES(FILE_MGMT_CD)
	    , UPDATE_NO   		= #{token.gv_userId}
	    , UPDATE_DATE 		= NOW()
